import type { Report, ReportPreview, MacroSkill } from '../types/game';

// ─── Helper ───────────────────────────────────────────────────────────────────

type SkillTuple = [number, string, string[], string[]];

function mkPreview(
  score: number, tag: string, summary: string,
  da: SkillTuple, ux: SkillTuple, ts: SkillTuple, sm: SkillTuple,
  market: Record<string, string>
): ReportPreview {
  const skill = (name: string, icon: string, color: string, textColor: string, t: SkillTuple): MacroSkill => ({
    name, icon, score: t[0], color, textColor, summary: t[1], strengths: t[2], weaknesses: t[3],
  });
  return {
    overallScore: score, tag, summary,
    macroSkills: [
      skill('Design & Art',        'fa-palette',    'from-purple-500/15 to-violet-600/10', 'text-purple-400', da),
      skill('User Experience',     'fa-user-circle','from-sky-500/15 to-cyan-600/10',      'text-sky-400',    ux),
      skill('Technology & Systems','fa-microchip',  'from-emerald-500/15 to-green-600/10', 'text-emerald-400',ts),
      skill('Strategy & Market',   'fa-chart-line', 'from-amber-500/15 to-orange-600/10',  'text-amber-400',  sm),
    ],
    market,
  };
}

